
  create table "public"."child_portal_tokens" (
    "id" bigint generated by default as identity not null,
    "account_id" bigint not null,
    "created_at" timestamp with time zone not null default now(),
    "child_id" bigint not null,
    "token" text not null,
    "revoked_at" timestamp with time zone
      );


alter table "public"."child_portal_tokens" enable row level security;

CREATE INDEX child_portal_tokens_account_id_idx ON public.child_portal_tokens USING btree (account_id);

CREATE INDEX child_portal_tokens_child_id_idx ON public.child_portal_tokens USING btree (account_id, child_id);

CREATE UNIQUE INDEX child_portal_tokens_pkey ON public.child_portal_tokens USING btree (id);

CREATE UNIQUE INDEX child_portal_tokens_token_key ON public.child_portal_tokens USING btree (token);

alter table "public"."child_portal_tokens" add constraint "child_portal_tokens_pkey" PRIMARY KEY using index "child_portal_tokens_pkey";

alter table "public"."child_portal_tokens" add constraint "child_portal_tokens_account_id_fkey" FOREIGN KEY (account_id) REFERENCES public.accounts(id) ON DELETE CASCADE not valid;

alter table "public"."child_portal_tokens" validate constraint "child_portal_tokens_account_id_fkey";

alter table "public"."child_portal_tokens" add constraint "child_portal_tokens_child_id_fkey" FOREIGN KEY (account_id, child_id) REFERENCES public.children(account_id, id) ON DELETE CASCADE not valid;

alter table "public"."child_portal_tokens" validate constraint "child_portal_tokens_child_id_fkey";

alter table "public"."child_portal_tokens" add constraint "child_portal_tokens_token_key" UNIQUE using index "child_portal_tokens_token_key";

set check_function_bodies = off;

CREATE OR REPLACE FUNCTION public.get_child_portal(p_token text)
 RETURNS jsonb
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO ''
AS $function$
declare
  v_child public.children;
  v_account_id bigint;
  v_suggestions jsonb;
begin
  -- Treat the token as untrusted input. A too-short value cannot be a real
  -- 48-char token, so reject it before touching any table.
  if p_token is null or length(p_token) < 24 then
    return null;
  end if;

  select c.* into v_child
  from public.child_portal_tokens t
    join public.children c
      on c.id = t.child_id and c.account_id = t.account_id
  where t.token = p_token
    and t.revoked_at is null;

  if not found then
    return null;
  end if;

  v_account_id := v_child.account_id;

  select coalesce(
    jsonb_agg(to_jsonb(x) order by x.redt_date desc nulls last),
    '[]'::jsonb
  )
  into v_suggestions
  from (
    select
      s.name_en,
      s.name_he,
      s.redt_date,
      case s.pipeline_state
        when 'look_into' then 'Being looked into'
        when 'unsure' then 'Still being considered'
        when 'yes' then 'Looking promising'
      end as status_label
    from public.shidduchim s
    where s.child_id = v_child.id
      and s.account_id = v_account_id
      and s.visibility = 'shared'
      and public.is_child_visible_state(s.pipeline_state)
  ) x;

  return jsonb_build_object(
    'child', jsonb_build_object(
      'first_name_en', v_child.first_name_en,
      'first_name_he', v_child.first_name_he
    ),
    'suggestions', v_suggestions
  );
end;
$function$
;

CREATE OR REPLACE FUNCTION public.set_child_portal_token_defaults()
 RETURNS trigger
 LANGUAGE plpgsql
 SET search_path TO ''
AS $function$
begin
  if new.account_id is null then
    new.account_id := public.current_account_id();
  end if;
  new.token := encode(extensions.gen_random_bytes(24), 'hex');
  return new;
end;
$function$
;

-- HAND-FIXED (E7): db diff / migra does not emit the `revoke` half, so the
-- fork's default privileges would silently leave anon AND authenticated with the
-- full DML set (incl. DELETE + TRUNCATE, which bypasses RLS) on the token table
-- at CREATE time. Revoke-all-then-regrant is the only correct shape — it mirrors
-- 06_grants.sql exactly. anon must reach NOTHING on this table; the token column
-- is the secret. DELETE is withheld from authenticated so a revoked token stays
-- as an audit trail.
revoke all on table "public"."child_portal_tokens" from anon, authenticated;
grant select, insert, update on table "public"."child_portal_tokens" to authenticated;
grant all on table "public"."child_portal_tokens" to service_role;

-- Identity sequence: authenticated mints its own tokens; anon never inserts.
revoke all on sequence "public"."child_portal_tokens_id_seq" from anon;
grant usage, select on sequence "public"."child_portal_tokens_id_seq" to authenticated;
grant all on sequence "public"."child_portal_tokens_id_seq" to service_role;

-- Trigger fn: executable by authenticated + service_role, never anon.
revoke all on function public.set_child_portal_token_defaults() from public, anon;
grant execute on function public.set_child_portal_token_defaults() to authenticated;
grant execute on function public.set_child_portal_token_defaults() to service_role;

-- get_child_portal() is the ONE function anon may run — the only anon-reachable
-- read path over portal data. Revoke from public first, then grant explicitly.
revoke all on function public.get_child_portal(text) from public;
grant execute on function public.get_child_portal(text) to anon;
grant execute on function public.get_child_portal(text) to authenticated;
grant execute on function public.get_child_portal(text) to service_role;


  create policy "Child portal tokens scoped to account"
  on "public"."child_portal_tokens"
  as permissive
  for all
  to authenticated
using ((account_id = public.current_account_id()))
with check ((account_id = public.current_account_id()));


CREATE TRIGGER set_child_portal_token_defaults BEFORE INSERT ON public.child_portal_tokens FOR EACH ROW EXECUTE FUNCTION public.set_child_portal_token_defaults();


